const input = items[0].json || {};
const bot = String(input.bot_message || '').trim();
const user = String(input.user_message || '').trim();
const ctx = Array.isArray(input.contexto_conversa) ? input.contexto_conversa : [];

function normText(s) {
  return String(s || '').replace(/\s+/g, ' ').trim();
}

function short(s, n) {
  return normText(s).slice(0, n);
}

const contextLines = ctx
  .slice(-8)
  .map((m, i) => {
    const u = short(m.user_message || '', 180);
    const b = short(m.bot_message || '', 260);
    return `${i + 1}. U: ${u || '-'} | B: ${b || '-'}`;
  });

const prices = [];
let m;
const rePreco = /R\$\s?([\d.,]+)/g;
while ((m = rePreco.exec(bot)) !== null) prices.push(m[1]);

const signals = {
  has_price: /R\$/i.test(bot),
  has_budget: /total|orcamento|orçamento|subtotal|itens?/i.test(bot) && /R\$/i.test(bot),
  has_not_found: /nao encontr|não encontr|nao temos|não temos|indisponivel|indisponível/i.test(bot),
  has_vendor_handoff: /vou chamar|encaminhei|encaminhar.*vendedor|vendedor|atendente|consultor/i.test(bot),
  user_wants_vendor: /vendedor|atendente|consultor|encaminhar|humano/i.test(user),
  user_accepts: /fecha|quero esse|pode separar|vou levar|esse mesmo|pode fechar/i.test(user),
  user_asks_discount: /mais barato|mais em conta|desconto|caro|preco alto|preço alto/i.test(user),
  greeting_noise: /^(oi|ola|olá|bom dia|boa tarde|boa noite|ok|blz|valeu|obrigado|obg|show)\W*$/i.test(user) && !/R\$/i.test(bot),
};

if (signals.greeting_noise) {
  return [];
}

const prompt = [
  'Voce e um classificador de atendimento de loja de tintas.',
  'Responda APENAS JSON valido, sem markdown e sem explicacoes.',
  '',
  'EVENTOS PERMITIDOS (escolha 1):',
  '- busca_produto',
  '- produto_nao_encontrado_ia',
  '- orcamento_gerado',
  '- orcamento_aceito',
  '- pedido_desconto',
  '- handoff_vendedor',
  '- fora_escopo',
  '',
  'REGRAS:',
  '1) Se cliente confirma fechamento -> orcamento_aceito.',
  '2) Se IA nao encontra/nao tem item solicitado -> produto_nao_encontrado_ia.',
  '3) Se IA gera itens+precos+total -> orcamento_gerado.',
  '4) Se cliente pede preco menor -> pedido_desconto.',
  '5) Se IA encaminha vendedor ou cliente pede humano -> handoff_vendedor.',
  '6) Se ha preco sem fechamento -> busca_produto.',
  '',
  'FORMATO EXATO:',
  '{"evento":"...","produtos_buscados":[{"nome":""}],"produtos_nao_encontrados_ia":[{"nome":""}],"produtos_ofertados":[{"nome":"","marca":"","preco":"","volume":""}],"valor_total":null,"sentimento":"neutro","detalhes":"resumo curto"}',
  '',
  'RESTRICOES:',
  '- maximo 12 itens por lista',
  '- produtos_* sempre array',
  '- valor_total numero ou null',
  '- sentimento: positivo | neutro | negativo',
  '',
  'ULTIMA MENSAGEM CLIENTE: ' + JSON.stringify(user.slice(0, 600)),
  'ULTIMA MENSAGEM IA: ' + JSON.stringify(bot.slice(0, 1400)),
  'CONTEXTO RECENTE:',
  contextLines.join('\n') || '(sem contexto)',
  'SINAIS: ' + JSON.stringify(signals),
  'PRECOS: ' + JSON.stringify(prices)
].join('\n');

return [{
  json: {
    ...input,
    _classificacao_prompt: prompt,
    _classificacao_signals: signals,
    _precos_detectados: prices,
    _context_size: ctx.length,
  }
}];

const src = $('Extrair e Preparar').first().json;
const rawObj = items[0].json || {};
const rawText = String(rawObj.text ?? rawObj.response ?? rawObj.output ?? '');

const EVENTOS = [
  'busca_produto',
  'produto_nao_encontrado_ia',
  'orcamento_gerado',
  'orcamento_aceito',
  'pedido_desconto',
  'handoff_vendedor',
  'fora_escopo'
];

const EVENTO_ALIAS = {
  pediu_mais_barato: 'pedido_desconto',
  pediu_vendedor: 'handoff_vendedor',
  produto_nao_encontrado: 'produto_nao_encontrado_ia'
};

const SENTIMENTOS = ['positivo', 'neutro', 'negativo'];

function parseModelJson(text) {
  if (!text) return null;
  const clean = text.replace(/```json/gi, '').replace(/```/g, '').trim();
  try { return JSON.parse(clean); } catch (_) {}
  const first = clean.indexOf('{');
  const last = clean.lastIndexOf('}');
  if (first >= 0 && last > first) {
    try { return JSON.parse(clean.slice(first, last + 1)); } catch (_) {}
  }
  return null;
}

function toNumber(v) {
  if (v === null || v === undefined || v === '') return null;
  if (typeof v === 'number') return Number.isFinite(v) ? v : null;
  const n = parseFloat(String(v).replace(/[^\d,.-]/g, '').replace(',', '.'));
  return Number.isFinite(n) ? n : null;
}

function normalizeNameList(v) {
  const arr = Array.isArray(v) ? v : (v && typeof v === 'object' ? [v] : []);
  return arr
    .map((p) => {
      if (typeof p === 'string') {
        const nome = p.trim();
        return nome ? { nome } : null;
      }
      const nome = String(p?.nome ?? '').trim();
      return nome ? { nome } : null;
    })
    .filter(Boolean)
    .slice(0, 12);
}

function normalizeProdutosOfertados(v) {
  const arr = Array.isArray(v) ? v : (v && typeof v === 'object' ? [v] : []);
  return arr
    .map((p) => {
      const nome = String(p?.nome ?? '').trim();
      const marca = String(p?.marca ?? '').trim();
      const preco = String(p?.preco ?? '').trim();
      const volume = String(p?.volume ?? '').trim();
      if (!nome && !marca && !preco && !volume) return null;
      return { nome, marca, preco, volume };
    })
    .filter(Boolean)
    .slice(0, 12);
}

function extractRequestedFromUser(user) {
  const txt = String(user || '').replace(/\n+/g, ' | ');
  const parts = txt.split(/[,;|]/g).map((s) => s.trim()).filter(Boolean);
  const picked = [];
  const re = /(tinta|rolo|massa|fita|lixa|verniz|selador|esmalte|fundo|spray|pincel|trincha|bandeja|cimento queimado|coral|suvinil|tmc)/i;
  for (const p of parts) {
    if (re.test(p)) picked.push({ nome: p.slice(0, 120) });
    if (picked.length >= 12) break;
  }
  return picked;
}

function mapEvento(evtRaw) {
  const low = String(evtRaw || '').trim().toLowerCase();
  const mapped = EVENTO_ALIAS[low] || low;
  return EVENTOS.includes(mapped) ? mapped : '';
}

function inferEvento(parsed, user, bot) {
  const mapped = mapEvento(parsed?.evento);
  if (mapped) return mapped;

  if (/fecha|quero esse|pode separar|vou levar|esse mesmo|pode fechar/i.test(user)) return 'orcamento_aceito';
  if (/mais barato|mais em conta|desconto|caro|preco alto|preço alto/i.test(user)) return 'pedido_desconto';
  if (/vou chamar|encaminhei|encaminhar.*vendedor|vendedor|atendente|consultor/i.test(bot) || /vendedor|atendente|consultor|encaminhar|humano/i.test(user)) return 'handoff_vendedor';
  if (/nao encontr|não encontr|nao temos|não temos|indisponivel|indisponível/i.test(bot)) return 'produto_nao_encontrado_ia';
  if (/total|orcamento|orçamento|subtotal|itens?/i.test(bot) && /R\$/i.test(bot)) return 'orcamento_gerado';
  if (/R\$/i.test(bot)) return 'busca_produto';
  return 'fora_escopo';
}

function inferSentimento(parsedSentimento, user) {
  let s = String(parsedSentimento ?? 'neutro').trim().toLowerCase();
  if (SENTIMENTOS.includes(s)) return s;
