  if (/ruim|horrivel|horrível|péssimo|pessimo|reclama/i.test(user)) return 'negativo';
  return 'neutro';
}

function inferMotivoVendedor(evento, user, bot) {
  if (evento !== 'handoff_vendedor') return null;
  if (/vendedor|atendente|consultor|encaminhar|humano/i.test(user)) return 'pedido_explicito_cliente';
  if (/nao encontr|não encontr|nao temos|não temos|indisponivel|indisponível/i.test(bot)) return 'indisponibilidade_produto';
  if (/mais barato|mais em conta|desconto|caro|preco alto|preço alto/i.test(user)) return 'negociacao_preco';
  if (/frete|entrega|retirada/i.test(bot)) return 'duvida_logistica';
  return 'transferencia_automatica';
}

function hasOrcamentoNoContexto(ctx) {
  if (!Array.isArray(ctx)) return false;
  return ctx.some((m) => {
    const b = String(m?.bot_message || '');
    return /total|orcamento|orçamento|subtotal|itens?/i.test(b) && /R\$/i.test(b);
  });
}

