if (evento === 'produto_nao_encontrado_ia' && produtos_nao_encontrados_ia.length === 0) {
  produtos_nao_encontrados_ia = produtos_buscados.slice(0, 12);
}

const valor_total = toNumber(parsed.valor_total);
const sentimento = inferSentimento(parsed.sentimento, user);
const motivo_acionamento_vendedor = inferMotivoVendedor(evento, user, bot);

const hasOrcamentoAtual = /total|orcamento|orçamento|subtotal|itens?/i.test(bot) && /R\$/i.test(bot);
const handoff_qualificado = evento === 'handoff_vendedor'
  ? (hasOrcamentoAtual || hasOrcamentoNoContexto(contexto))
  : null;

let detalhes = String(parsed.detalhes ?? '').trim();
if (!detalhes) {
  detalhes = evento === 'handoff_vendedor' && motivo_acionamento_vendedor
    ? `workflow_v3: motivo=${motivo_acionamento_vendedor}`
    : `workflow_v3: classificacao_auto=${evento}`;
}
if (detalhes.length > 500) detalhes = detalhes.slice(0, 500);

